        let lines = vec!["# Title", "content line"];
        let sections = parse_markdown_sections(&lines);
        assert_eq!(sections.len(), 1);
        assert_eq!(sections[0].title, "Title");
        assert_eq!(sections[0].depth, 0);
    }

    #[test]
    fn parse_multiple_headings() {
