//! Plain text section parsing for progressive disclosure.

use crate::calculate_tokens;
use crate::disclosure::types::Section;

/// Parse plain-text content into paragraph sections.
///
/// Groups text by blank-line-separated paragraphs. If the entire document
/// is one paragraph (no blank lines) and has more than 50 lines, chunks by 50.
pub fn parse_text_sections(lines: &[&str]) -> Vec<Section> {
    let mut sections: Vec<Section> = Vec::new();
    let mut current_start: usize = 0;
    let mut paragraph_num: usize = 0;

    for i in 0..=lines.len() {
        let is_blank = i == lines.len() || lines[i].trim().is_empty();
        if is_blank && i > current_start {
            paragraph_num += 1;
            let section_content = lines[current_start..i].join("\n");
            sections.push(Section {
                title: format!("Paragraph {paragraph_num}"),
                depth: 0,
                start_line: current_start + 1,
                end_line: i,
                token_count: calculate_tokens(&section_content),
                section_type: "heading".to_string(),
            });
        }
        if is_blank {
            current_start = i + 1;
        }
    }

    // If the entire document is one paragraph (or no sections), chunk by 50 lines
    if sections.len() <= 1 && lines.len() > 50 {
        sections.clear();
        let chunk_size = 50usize;
        let mut chunk_num = 0usize;
        let mut i = 0usize;

        while i < lines.len() {
            chunk_num += 1;
            let end = (i + chunk_size).min(lines.len());
            let section_content = lines[i..end].join("\n");
            sections.push(Section {
                title: format!("Lines {}-{}", i + 1, end),
                depth: 0,
                start_line: i + 1,
                end_line: end,
                token_count: calculate_tokens(&section_content),
                section_type: "heading".to_string(),
            });
            i = end;
            let _ = chunk_num; // suppress warning
        }
    }

    sections
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn text_paragraphs() {
        let lines = vec!["para1 line1", "para1 line2", "", "para2 line1"];
        let sections = parse_text_sections(&lines);
        assert_eq!(sections.len(), 2);
        assert_eq!(sections[0].title, "Paragraph 1");
        assert_eq!(sections[1].title, "Paragraph 2");
    }

    #[test]
    fn text_chunks_long_doc() {
        let lines: Vec<&str> = (0..100).map(|_| "text").collect();
        let sections = parse_text_sections(&lines);
        // 100 / 50 = 2 chunks
        assert_eq!(sections.len(), 2);
        assert_eq!(sections[0].title, "Lines 1-50");
        assert_eq!(sections[1].title, "Lines 51-100");
    }

    #[test]
    fn text_empty() {
        let sections = parse_text_sections(&[]);
        assert!(sections.is_empty());
    }
}

//! Shared types for the disclosure module.

use serde::{Deserialize, Serialize};

/// A logical section identified within a document.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Section {
    /// Display title of the section.
    pub title: String,
    /// Nesting depth (0-based).
    pub depth: u32,
    /// 1-based line number where the section begins.
    pub start_line: usize,
    /// 1-based line number where the section ends (inclusive).
    pub end_line: usize,
    /// Estimated token count for the section content.
    pub token_count: u32,
    /// Structural type of the section.
    #[serde(rename = "type")]
    pub section_type: String,
}

/// High-level structural overview of a document.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct DocumentOverview {
    /// The detected document format.
    pub format: String,
    /// Total number of lines in the document.
    pub line_count: usize,
    /// Estimated total token count.
    pub token_count: u32,
    /// Ordered list of sections.
    pub sections: Vec<Section>,
    /// Top-level JSON keys (JSON documents only).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub keys: Option<Vec<JsonKey>>,
    /// Markdown table of contents (markdown documents only).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub toc: Option<Vec<TocEntry>>,
}

/// A JSON key with type info and a preview value.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct JsonKey {
    pub key: String,
    #[serde(rename = "type")]
    pub key_type: String,
    pub preview: String,
}

/// A table-of-contents entry for markdown documents.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct TocEntry {
    pub title: String,
    pub depth: u32,
    pub line: usize,
}

/// A single search match.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SearchResult {
    /// 1-based line number of the matching line.
    pub line: usize,
    /// The full text of the matching line.
    pub content: String,
    /// Lines immediately preceding the match.
    pub context_before: Vec<String>,
    /// Lines immediately following the match.
    pub context_after: Vec<String>,
}

/// Result of extracting a line range from a document.
