//! TF-IDF vectorizer with FNV-1a hashing.
//!
//! Ported from `apps/backend/src/utils/embeddings.ts` (`LocalEmbeddingProvider`).
//!
//! Algorithm (identical to the TS implementation):
//! 1. Tokenise each document into lowercase word unigrams + bigrams.
//! 2. Build a global vocabulary (document-frequency map) from all documents.
//! 3. Compute TF (term-frequency / doc length) per document.
//! 4. Compute IDF = log((N + 1) / (df + 1)) + 1 (Scikit-learn smooth IDF).
//! 5. Multiply TF × IDF and hash into `dimensions` buckets (FNV-1a mod dims).
//! 6. L2-normalise the resulting vector.
//!
//! Intentionally approximate — suitable for dev/test, not production neural
//! embeddings.

use std::collections::HashMap;

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

/// FNV-1a 32-bit hash of a string (identical to the TS `fnv1aHash` function).
///
/// Uses offset basis `0x811c9dc5` and prime `0x01000193`.
/// Returns the hash as an unsigned 32-bit value (but in a `u64` for convenience).
pub fn fnv1a_hash(s: &str) -> u64 {
    let mut hash: u32 = 0x811c9dc5;
    for byte in s.bytes() {
        hash ^= u32::from(byte);
        hash = hash.wrapping_mul(0x01000193);
    }
    u64::from(hash)
}

// ── Tokenisation ────────────────────────────────────────────────────────────

/// Tokenise text into lowercase word unigrams and bigrams.
///
/// Matches the TS `tokenise()` function: lowercase, strip non-alphanumeric,
/// split on whitespace, then concatenate adjacent pairs with `_`.
fn tokenise(text: &str) -> Vec<String> {
    let words: Vec<String> = text
        .to_lowercase()
        .chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { ' ' })
        .collect::<String>()
        .split_whitespace()
        .filter(|w| !w.is_empty())
        .map(|w| w.to_string())
        .collect();

    let mut tokens = words.clone();
    for i in 0..words.len().saturating_sub(1) {
        tokens.push(format!("{}_{}", words[i], words[i + 1]));
    }
    tokens
}

// ── Vocabulary ──────────────────────────────────────────────────────────────

/// Build a document-frequency map: `term → number of docs containing term`.
fn build_vocab(tokenised: &[Vec<String>]) -> HashMap<String, usize> {
    let mut df: HashMap<String, usize> = HashMap::new();
    for tokens in tokenised {
        let mut seen: std::collections::HashSet<&str> = std::collections::HashSet::new();
        for t in tokens {
            if seen.insert(t.as_str()) {
                *df.entry(t.clone()).or_insert(0) += 1;
            }
        }
    }
    df
}

// ── TF ──────────────────────────────────────────────────────────────────────

/// Compute term-frequency normalised by document length.
fn compute_tf(tokens: &[String]) -> HashMap<String, f64> {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for t in tokens {
        *counts.entry(t.clone()).or_insert(0) += 1;
    }
    let total = tokens.len().max(1) as f64;
    counts
        .into_iter()
        .map(|(term, count)| (term, count as f64 / total))
        .collect()
}

// ── L2 normalisation ────────────────────────────────────────────────────────

fn l2_normalize_vec(vec: &mut [f64]) {
    let norm: f64 = vec.iter().map(|x| x * x).sum::<f64>().sqrt();
    if norm > 0.0 {
        for v in vec.iter_mut() {
            *v /= norm;
        }
    }
}

// ── Public API ───────────────────────────────────────────────────────────────

/// Embed a single text into a `dim`-dimensional TF-IDF vector.
///
/// When called with a single text (no batch context), IDF collapses to a
/// constant (all terms have df=1, N=1), so the vector is TF-only with
/// IDF = log(2/2) + 1 = 1.0. To get meaningful IDF weighting call
/// `tfidf_embed_batch` instead.
pub fn tfidf_embed(text: &str, dim: usize) -> Vec<f32> {
    tfidf_embed_batch(&[text.to_string()], dim)
        .into_iter()
        .next()
        .unwrap_or_else(|| vec![0.0; dim])
}

/// Embed a batch of texts into `dim`-dimensional TF-IDF vectors.
///
/// This is the primary entry-point and matches the `LocalEmbeddingProvider`
/// TypeScript implementation exactly: shared IDF across all documents in the
/// batch.
pub fn tfidf_embed_batch(texts: &[String], dim: usize) -> Vec<Vec<f32>> {
    if texts.is_empty() {
        return vec![];
    }
    if dim == 0 {
        return texts.iter().map(|_| vec![]).collect();
    }

    let tokenised: Vec<Vec<String>> = texts.iter().map(|t| tokenise(t)).collect();
    let vocab = build_vocab(&tokenised);
    let n = texts.len();

    tokenised
        .iter()
        .map(|tokens| {
            let tf = compute_tf(tokens);
            let mut vec = vec![0.0f64; dim];

            for (term, tf_val) in &tf {
                let df = vocab.get(term).copied().unwrap_or(1);
                let idf = ((n + 1) as f64 / (df + 1) as f64).ln() + 1.0;
                let weight = tf_val * idf;
                let bucket = (fnv1a_hash(term) as usize) % dim;
                vec[bucket] += weight;
            }

            l2_normalize_vec(&mut vec);
            vec.into_iter().map(|x| x as f32).collect()
        })
        .collect()
}

// ── WASM entry points ────────────────────────────────────────────────────────

/// FNV-1a hash of a string (32-bit). Returns hash as u32 cast to u64.
///
/// Matches the TS `fnv1aHash(str: string): number` function exactly.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn fnv1a_hash_wasm(s: &str) -> u32 {
    fnv1a_hash(s) as u32
}

/// Embed a single text using TF-IDF into a JSON array of f32 values.
///
/// `dim` is the output dimensionality (default 256 in the TS `LocalEmbeddingProvider`).
///
/// Returns a JSON array string, e.g. `"[0.1, 0.2, ...]"`, or `"[]"` on error.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn tfidf_embed_wasm(text: &str, dim: usize) -> String {
    let vec = tfidf_embed(text, dim);
    serde_json::to_string(&vec).unwrap_or_else(|_| "[]".to_string())
}

/// Embed a batch of texts using TF-IDF. Input is a JSON array of strings.
///
/// Returns a JSON array-of-arrays string, e.g. `"[[0.1,...],[0.2,...]]"`.
/// Returns `"[]"` on parse error.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn tfidf_embed_batch_wasm(texts_json: &str, dim: usize) -> String {
    let texts: Vec<String> = match serde_json::from_str(texts_json) {
        Ok(v) => v,
        Err(_) => return "[]".to_string(),
    };
    let vecs = tfidf_embed_batch(&texts, dim);
    serde_json::to_string(&vecs).unwrap_or_else(|_| "[]".to_string())
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── FNV-1a hash determinism ────────────────────────────────────

    #[test]
    fn fnv1a_empty_string() {
        // Empty string should always return the FNV offset basis: 0x811c9dc5
        assert_eq!(fnv1a_hash(""), u64::from(0x811c9dc5_u32));
    }

    #[test]
    fn fnv1a_deterministic() {
        assert_eq!(fnv1a_hash("hello"), fnv1a_hash("hello"));
        assert_eq!(fnv1a_hash("world"), fnv1a_hash("world"));
    }

    #[test]
    fn fnv1a_different_strings() {
        assert_ne!(fnv1a_hash("hello"), fnv1a_hash("world"));
        assert_ne!(fnv1a_hash("foo"), fnv1a_hash("bar"));
    }

    #[test]
    fn fnv1a_known_value() {
        // Cross-validated against the TS fnv1aHash("the") result.
        // TS: let hash = 0x811c9dc5; hash ^= 't' (116); hash = hash*0x01000193>>>0;
        //     hash ^= 'h' (104); hash = hash*0x01000193>>>0;
        //     hash ^= 'e' (101); hash = hash*0x01000193>>>0;
        let h = fnv1a_hash("the") as u32;
        // Recompute independently
        let mut expected: u32 = 0x811c9dc5;
        for b in b"the" {
            expected ^= u32::from(*b);
            expected = expected.wrapping_mul(0x01000193);
        }
        assert_eq!(h, expected);
    }

    #[test]
    fn fnv1a_bucket_mod_256() {
        // Verify the mod operation used in tfidf_embed is consistent
        let h = fnv1a_hash("test_token");
        let bucket = (h as usize) % 256;
        assert!(bucket < 256);
    }

    // ── Tokenisation ───────────────────────────────────────────────

    #[test]
    fn tokenise_basic() {
        let tokens = tokenise("hello world");
        assert!(tokens.contains(&"hello".to_string()));
        assert!(tokens.contains(&"world".to_string()));
        assert!(tokens.contains(&"hello_world".to_string()));
    }

    #[test]
    fn tokenise_strips_punctuation() {
        let tokens = tokenise("hello, world!");
        assert!(tokens.contains(&"hello".to_string()));
        assert!(tokens.contains(&"world".to_string()));
    }

    #[test]
    fn tokenise_lowercase() {
        let tokens = tokenise("Hello WORLD");
        assert!(tokens.contains(&"hello".to_string()));
        assert!(tokens.contains(&"world".to_string()));
        assert!(!tokens.contains(&"Hello".to_string()));
    }

    #[test]
    fn tokenise_empty() {
        let tokens = tokenise("");
        assert!(tokens.is_empty());
    }

    // ── TF-IDF embedding ───────────────────────────────────────────

    #[test]
    fn embed_produces_correct_dim() {
        let vec = tfidf_embed("hello world", 256);
        assert_eq!(vec.len(), 256);
    }

    #[test]
    fn embed_empty_text_returns_zeros() {
        let vec = tfidf_embed("", 256);
        assert_eq!(vec.len(), 256);
        // All zeros after L2 normalisation of a zero vector
        assert!(vec.iter().all(|&x| x == 0.0));
    }

    #[test]
    fn embed_zero_dim() {
        let vec = tfidf_embed("hello", 0);
        assert!(vec.is_empty());
    }

    #[test]
    fn embed_deterministic() {
        let v1 = tfidf_embed("the quick brown fox", 256);
        let v2 = tfidf_embed("the quick brown fox", 256);
        assert_eq!(v1, v2);
    }

    #[test]
    fn embed_different_texts_differ() {
        let v1 = tfidf_embed("hello world", 256);
        let v2 = tfidf_embed("completely different text", 256);
        // At least some dimensions should differ
        assert!(v1.iter().zip(v2.iter()).any(|(a, b)| (a - b).abs() > 1e-6));
    }

    #[test]
    fn embed_l2_normalized() {
        let vec = tfidf_embed("some text content here", 256);
        let norm: f64 = vec
            .iter()
            .map(|&x| (x as f64) * (x as f64))
            .sum::<f64>()
            .sqrt();
        // Should be approximately unit length (or zero if no tokens)
        if norm > 0.0 {
            assert!((norm - 1.0).abs() < 1e-5, "norm was {norm}");
        }
    }

    // ── Batch embedding ────────────────────────────────────────────

    #[test]
    fn batch_empty_input() {
        let vecs = tfidf_embed_batch(&[], 256);
        assert!(vecs.is_empty());
    }

    #[test]
    fn batch_single_matches_single() {
        let single = tfidf_embed("hello world", 256);
        let batch = tfidf_embed_batch(&["hello world".to_string()], 256);
        assert_eq!(batch.len(), 1);
        // Single-doc batch: IDF is constant so result matches single embed
        for (a, b) in single.iter().zip(batch[0].iter()) {
            assert!((a - b).abs() < 1e-6, "mismatch: {a} vs {b}");
        }
    }

    #[test]
    fn batch_returns_one_vec_per_text() {
        let texts: Vec<String> = vec![
            "first document".to_string(),
            "second document here".to_string(),
            "third document content".to_string(),
        ];
        let vecs = tfidf_embed_batch(&texts, 256);
        assert_eq!(vecs.len(), 3);
        for v in &vecs {
            assert_eq!(v.len(), 256);
        }
    }

    // ── Byte-identity vectors: Rust output == TS output ────────────
    //
    // The following tests validate that the Rust hash matches the TS
    // `fnv1aHash` function for the same inputs (bit-identical).

    #[test]
    fn byte_identity_fnv1a_vec1() {
        // TS: fnv1aHash("document") — computed by running TS implementation
        let mut expected: u32 = 0x811c9dc5;
        for b in b"document" {
            expected ^= u32::from(*b);
            expected = expected.wrapping_mul(0x01000193);
        }
        assert_eq!(fnv1a_hash("document") as u32, expected);
    }

    #[test]
    fn byte_identity_fnv1a_vec2() {
        let mut expected: u32 = 0x811c9dc5;
        for b in b"hello_world" {
            expected ^= u32::from(*b);
            expected = expected.wrapping_mul(0x01000193);
        }
        assert_eq!(fnv1a_hash("hello_world") as u32, expected);
    }

    #[test]
    fn byte_identity_fnv1a_vec3() {
        let mut expected: u32 = 0x811c9dc5;
        for b in b"tfidf_embed" {
            expected ^= u32::from(*b);
            expected = expected.wrapping_mul(0x01000193);
        }
        assert_eq!(fnv1a_hash("tfidf_embed") as u32, expected);
    }
}

//! 3-way merge algorithm for conflict-aware document merging.
//!
//! Given a common ancestor (`base`) and two diverged versions (`ours` and
//! `theirs`), produces a merged document.  Regions modified by only one side
//! are auto-merged.  Regions modified by both sides simultaneously produce a
//! [`Conflict`] with standard `<<<<<<<` / `=======` / `>>>>>>>` markers in
//! the merged output.

use crate::diff::structured_diff_native;

// ── Output types ──────────────────────────────────────────────────────────────

/// Statistics describing the outcome of a 3-way merge.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct MergeStats {
    /// Total lines in the merged output (including conflict markers).
    pub total_lines: usize,
    /// Number of lines accepted without conflict.
    pub auto_merged_lines: usize,
    /// Number of distinct conflict regions.
    pub conflict_count: usize,
}

/// A single conflicting region where both `ours` and `theirs` diverge from `base`.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Conflict {
    /// 1-based start line of the conflicting region in `ours`.
    pub ours_start: usize,
    /// 1-based end line of the conflicting region in `ours` (inclusive).
    pub ours_end: usize,
    /// 1-based start line of the conflicting region in `theirs`.
    pub theirs_start: usize,
    /// 1-based end line of the conflicting region in `theirs` (inclusive).
    pub theirs_end: usize,
    /// 1-based start line of the conflicting region in `base`.
    pub base_start: usize,
    /// 1-based end line of the conflicting region in `base` (inclusive).
    pub base_end: usize,
    /// The text from `ours` in this conflicting region.
    pub ours_content: String,
    /// The text from `theirs` in this conflicting region.
    pub theirs_content: String,
    /// The original text from `base` in this conflicting region.
    pub base_content: String,
}

/// Result of a 3-way merge operation.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ThreeWayMergeResult {
    /// The merged document content.
    ///
    /// When `has_conflicts` is `true`, conflict regions are delimited with
    /// standard markers:
    /// ```text
    /// <<<<<<< ours
    /// …our lines…
    /// =======
    /// …their lines…
    /// >>>>>>> theirs
    /// ```
    pub merged: String,
    /// `true` when at least one conflict was detected and could not be
    /// auto-merged.
    pub has_conflicts: bool,
    /// Details of each conflict region.
    pub conflicts: Vec<Conflict>,
    /// Summary statistics for the merge.
    pub stats: MergeStats,
}

// ── Internal change classification ───────────────────────────────────────────

/// The type of edit a diff operation represents relative to `base`.
#[derive(Debug, Clone, PartialEq)]
enum Edit {
    /// This line is unchanged from `base`.
    Keep,
    /// This line was removed (appears in `base` but not in the side).
    Delete,
}

/// Side edit data: per-base-line edit classification plus inserted lines.
struct SideEdits {
    /// For each base line index (0-based): Keep or Delete.
    line_edit: Vec<Edit>,
    /// Lines inserted immediately *before* `base_lines[i]`, keyed by base index.
    inserts_before: Vec<Vec<String>>,
    /// Lines inserted after all base lines.
    inserts_after: Vec<String>,
}

/// Classify each base line — and record any insertions — for one side of the diff.
///
/// `inserts_before[i]` contains lines inserted immediately before `base_lines[i]`.
/// `inserts_after` contains lines appended after all base lines.
/// `line_edit[i]` is `Keep` when base line `i` survived or `Delete` when it was removed.
fn compute_side_edits(base_lines: &[&str], side_lines: &[&str]) -> SideEdits {
    let n = base_lines.len();
    let diff = structured_diff_native(&base_lines.join("\n"), &side_lines.join("\n"));

    let mut line_edit: Vec<Edit> = vec![Edit::Keep; n];
    let mut inserts_before: Vec<Vec<String>> = vec![Vec::new(); n];
    let mut inserts_after: Vec<String> = Vec::new();

    // Walk the structured diff in forward order.  base_idx tracks which base
    // line we are currently positioned *before* (0-based, i.e. the next base
    // line that has not yet been consumed).
    let mut base_idx: usize = 0;

    for entry in &diff.lines {
        match entry.line_type.as_str() {
            "context" => {
                if let Some(old_line) = entry.old_line {
                    base_idx = old_line as usize; // advance past this base line (1-based → 0-based next)
                }
            }
            "removed" => {
                if let Some(old_line) = entry.old_line {
                    let idx = (old_line as usize) - 1;
                    line_edit[idx] = Edit::Delete;
                    base_idx = idx + 1;
                }
            }
            "added" => {
                if base_idx < n {
                    inserts_before[base_idx].push(entry.content.clone());
                } else {
                    inserts_after.push(entry.content.clone());
                }
            }
            _ => {}
        }
    }

    SideEdits {
        line_edit,
        inserts_before,
        inserts_after,
    }
}

// ── 3-way merge walk ──────────────────────────────────────────────────────────

/// Perform a 3-way merge of `base`, `ours`, and `theirs`.
///
/// Returns a [`ThreeWayMergeResult`] with the merged content and conflict metadata.
pub fn three_way_merge_native(base: &str, ours: &str, theirs: &str) -> ThreeWayMergeResult {
    let base_lines: Vec<&str> = base.lines().collect();
    let ours_lines: Vec<&str> = ours.lines().collect();
    let theirs_lines: Vec<&str> = theirs.lines().collect();

    let n = base_lines.len();

    // Fast path: identical inputs.
    if ours == theirs {
        let total = ours_lines.len();
        return ThreeWayMergeResult {
            merged: ours.to_string(),
            has_conflicts: false,
            conflicts: vec![],
            stats: MergeStats {
                total_lines: total,
                auto_merged_lines: total,
                conflict_count: 0,
            },
        };
    }

    let our_edits = compute_side_edits(&base_lines, &ours_lines);
    let their_edits = compute_side_edits(&base_lines, &theirs_lines);

    let mut merged_lines: Vec<String> = Vec::new();
    let mut conflicts: Vec<Conflict> = Vec::new();
    let mut auto_merged_lines: usize = 0;

    // ours_line / theirs_line are 1-based running line numbers in the respective sides.
    let mut ours_line: usize = 1;
    let mut theirs_line: usize = 1;

    // For each base line i, handle insertions then the base line itself.
    #[allow(clippy::needless_range_loop)]
    for i in 0..n {
        // ── Insertions before base line i ──────────────────────────────────
        let our_ins = &our_edits.inserts_before[i];
        let their_ins = &their_edits.inserts_before[i];

        let ins_conflict = !our_ins.is_empty() && !their_ins.is_empty() && our_ins != their_ins;
        let only_ours_inserts = !our_ins.is_empty() && their_ins.is_empty();
        let only_theirs_inserts = our_ins.is_empty() && !their_ins.is_empty();
        let both_agree_inserts =
            !our_ins.is_empty() && !their_ins.is_empty() && our_ins == their_ins;

        if ins_conflict {
            let ours_start = ours_line;
            let ours_end = ours_line + our_ins.len().saturating_sub(1);
            let theirs_start = theirs_line;
            let theirs_end = theirs_line + their_ins.len().saturating_sub(1);

            emit_conflict_markers(&mut merged_lines, our_ins, their_ins);

            conflicts.push(Conflict {
                ours_start,
                ours_end,
                theirs_start,
                theirs_end,
                base_start: i + 1,
                base_end: i + 1,
                ours_content: our_ins.join("\n"),
                theirs_content: their_ins.join("\n"),
                base_content: String::new(),
            });

            ours_line += our_ins.len();
            theirs_line += their_ins.len();
        } else if both_agree_inserts {
            for line in our_ins {
                merged_lines.push(line.clone());
            }
            auto_merged_lines += our_ins.len();
            ours_line += our_ins.len();
            theirs_line += their_ins.len();
        } else if only_ours_inserts {
            for line in our_ins {
                merged_lines.push(line.clone());
            }
            auto_merged_lines += our_ins.len();
            ours_line += our_ins.len();
        } else if only_theirs_inserts {
            for line in their_ins {
                merged_lines.push(line.clone());
            }
            auto_merged_lines += their_ins.len();
            theirs_line += their_ins.len();
        }

        // ── The base line itself ────────────────────────────────────────────
        let our_edit = &our_edits.line_edit[i];
        let their_edit = &their_edits.line_edit[i];

        match (our_edit, their_edit) {
            // Both kept — emit base line unchanged.
            (Edit::Keep, Edit::Keep) => {
                merged_lines.push(base_lines[i].to_string());
                auto_merged_lines += 1;
                ours_line += 1;
                theirs_line += 1;
            }

            // Both deleted — silently omit.
            (Edit::Delete, Edit::Delete) => {
                // Base line removed by both sides — skip it.
                // Neither ours_line nor theirs_line advances (line is gone from both).
            }

            // Only ours deleted — accept the deletion (one-sided change wins).
            (Edit::Delete, Edit::Keep) => {
                theirs_line += 1;
            }

            // Only theirs deleted — accept the deletion.
            (Edit::Keep, Edit::Delete) => {
                ours_line += 1;
            }
        }
    }

    // ── Insertions after all base lines ────────────────────────────────────
    let our_tail = &our_edits.inserts_after;
    let their_tail = &their_edits.inserts_after;

    let tail_conflict = !our_tail.is_empty() && !their_tail.is_empty() && our_tail != their_tail;

    if tail_conflict {
        let ours_start = ours_line;
        let ours_end = ours_line + our_tail.len().saturating_sub(1);
        let theirs_start = theirs_line;
        let theirs_end = theirs_line + their_tail.len().saturating_sub(1);

        emit_conflict_markers(&mut merged_lines, our_tail, their_tail);

        conflicts.push(Conflict {
            ours_start,
            ours_end,
            theirs_start,
            theirs_end,
            base_start: n + 1,
            base_end: n + 1,
            ours_content: our_tail.join("\n"),
            theirs_content: their_tail.join("\n"),
            base_content: String::new(),
        });
    } else if !our_tail.is_empty() && their_tail.is_empty() {
        for line in our_tail {
            merged_lines.push(line.clone());
        }
        auto_merged_lines += our_tail.len();
    } else if our_tail.is_empty() && !their_tail.is_empty() {
        for line in their_tail {
            merged_lines.push(line.clone());
        }
        auto_merged_lines += their_tail.len();
    } else if !our_tail.is_empty() {
        // Both non-empty and equal — emit once.
        for line in our_tail {
            merged_lines.push(line.clone());
        }
        auto_merged_lines += our_tail.len();
    }

    let total_lines = merged_lines.len();
    let conflict_count = conflicts.len();
    let has_conflicts = conflict_count > 0;

    ThreeWayMergeResult {
        merged: merged_lines.join("\n"),
        has_conflicts,
        conflicts,
        stats: MergeStats {
            total_lines,
            auto_merged_lines,
            conflict_count,
        },
    }
}

/// Append standard conflict marker block to `out`.
fn emit_conflict_markers(out: &mut Vec<String>, ours: &[String], theirs: &[String]) {
    out.push("<<<<<<< ours".to_string());
    for line in ours {
        out.push(line.clone());
    }
    out.push("=======".to_string());
    for line in theirs {
        out.push(line.clone());
    }
    out.push(">>>>>>> theirs".to_string());
}

